var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CITIZEN_EXTRA_M_NULL","text":{"KOREA":"속이 메스꺼워…….","JPN":"吐き気がする……","ENG":"I don't feel too good...","TWN":"我……我好難受……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_EXTRA_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_EXTRA_M_NULL","text":{"KOREA":"머리에서 목소리가 들려…… 하나가…… 돼야 해…….","JPN":"頭の中から声が聞こえる……一つに……なるんだ……","ENG":"I hear voices in my head... Must... become one...","TWN":"腦子裡有聲音……必須……合而為一……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_EXTRA_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>오랜</color> 갈구와 허기의 <color=#ff3636>끝</color>이 <color=#ff3636>마침</color>내 도래<b>했</b>다.","JPN":"<color=#ff3636>長い</color>渇きと飢えの<color=#ff3636>果て</color>が、<color=#ff3636>つい</color>に訪れ<b>た</b>のだ。","ENG":"The <color=#ff3636>long</color> thirst and hunger <b>are</b> <color=#ff3636>finally</color> coming to <color=#ff3636>an end</color>.","TWN":"<color=#ff3636>長久的</color>渴望與饑餓<color=#ff3636>終於</color>達<b>到</b>了盡<color=#ff3636>頭</color>。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>성찬</color>의 주<color=#ffd34c>인</color>이 도착<b>했</b>다. 군<color=#ff3636>주</color>께서 도래<color=#ffd34c>하였</color>다.","JPN":"<color=#ff3636>聖餐</color>の<color=#ffd34c>主</color>が到着<b>し</b>た。君<color=#ff3636>主様</color>のお出<color=#ffd34c>まし</color>だ。","ENG":"The <color=#ff3636>host</color> <b>of</b> the f<color=#ffd34c>e</color>ast has arri<color=#ffd34c>ve</color>d. The <color=#ff3636>mon</color>arch has arrived.","TWN":"<color=#ff3636>盛宴</color>的主<color=#ffd34c>人</color><b>到</b>了。君<color=#ff3636>主</color>已<color=#ffd34c>降臨</color>。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망치던 사람들이 모두…… 변해버렸어요.","JPN":"逃げ惑っていた人たちが皆……変わり果ててしまった。","ENG":"Everyone who tried to run away... is distorted.","TWN":"逃跑的人全都……變異了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"클리파 허수 에너지가 몸에 강제로 주입된 거예요.","JPN":"クリファ虚数エネルギーが体内に強制的に注入されたためです。","ENG":"They had Qlipha Imaginary Energy forcibly injected into their bodies.","TWN":"逆卡巴拉虛數能量被強行注入體內。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"적합자가 아닌 이들은 모두 몸이 무너져 내려 잔해가 되죠.","JPN":"身体が適応しなかった者は溶け落ち、残骸となってしまいます。","ENG":"Those who aren't suitable all turn into Remains.","TWN":"不合適的人都會崩潰變成殘骸。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그리고 무너져 내린 사람들에겐 <color=#ffd34c>정보 오염</color>현상이 발생해요.","JPN":"そして、溶け落ちた者には、<color=#ffd34c>情報汚染</color>が発生します。","ENG":"And for those people, a phenomenon called <color=#ffd34c>data corruption</color> also occurs.","TWN":"並且那些人會發生<color=#ffd34c>資訊污染</color>的現象。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어떤 대상에게 정보 오염이 발생하면 이 세계에 존재했던 대상에 대한 정보가 지워지고, 왜곡되죠.\xA0","JPN":"情報汚染が発生すると、現世に存在していた、その人物に関する情報は抹消され、捻じ曲げられるんです。\xA0","ENG":"When data corruption occurs on a target, all information that existed about the target is erased and distorted.\xA0","TWN":"當某個物件受到資訊污染時，所有關於這個個體的資訊就會被強行抹去或者扭曲掉。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"마치 그 사람이 세상에 존재하지 않았다는 것처럼.","JPN":"まるで、最初からこの世に存在していなかったかのように。","ENG":"As if that person had never existed in the first place.","TWN":"彷彿那個人從未存在於這個世界上一樣。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"정보 오염…… 그렇다면 내가 아버지를 기억하지 못하는 것도……?\xA0","JPN":"情報汚染……ということは、私がお父さんのことを覚えていないのも……？\xA0","ENG":"Data corruption... Maybe that's why I can't remember my father...?\xA0","TWN":"資訊污染……那麼我不記得爸爸的事也是……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"이쪽이다! 잔해들이 이쪽으로 모이고 있어!","JPN":"こっちだ！　残骸がここに集まってきているぞ！","ENG":"This way! The Remains are gathering over here!","TWN":"在這邊！殘骸正在往這邊聚集！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저 목소리는…….","JPN":"あの声は……","ENG":"That voice...","TWN":"那個聲音……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"분명 어디선가 들어본 것 같은 목소리예요.","JPN":"どこかで聞いたことがある。","ENG":"I think I've heard it somewhere before.","TWN":"那個聲音我肯定在哪聽過。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"확신할 수는 없지만…….","JPN":"確信は持てないけど……","ENG":"I can’t be certain, but...","TWN":"雖然無法肯定……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"머릿속 어둠이 시야를 가린다면…….","JPN":"頭の中の暗闇が視界を奪うのであれば……","ENG":"If the darkness in your mind blinds your vision...","TWN":"如果腦海中的黑暗遮蔽住視野……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그걸 정화하는 게 우리들의 임무예요.","JPN":"それを浄化するのが私たちの使命です。","ENG":"It's our duty to purify it.","TWN":"淨化它是我們的職責。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"가시죠. 길을 뚫는 것은 제 전문이니까.","JPN":"行きましょう。道を確保するのは私の専門ですから。","ENG":"Let's go. I'm an expert when it comes to paving roads.","TWN":"走吧，開路可是我的專長呢。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"낯이 익은 목소리라면, 분명 당신과 관련이 있는 사람일 거예요.","JPN":"親しみのある声ということは、あなたと関わりがあった人物だと思います。","ENG":"If you recognize the voice, I'm sure that person has some correlation with you.","TWN":"如果是熟悉的聲音，肯定是和你有關的人。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어쩌면 아버지일지도 모른다고 생각하고 계신 것 같은데, 그렇게 눈치 보지 않으셔도 돼요.","JPN":"お父さんかもしれないと思っているなら、正直にそう言ってください。","ENG":"I know you're thinking that he could be your father, so you don't have to be so careful around me.","TWN":"我知道你在想他可能是你的爸爸，在我面前不必那麼小心。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"맞아요. 아버지가 아닐까 생각하고는 있었죠.","JPN":"はい、お父さんなんじゃないかって思っています。","ENG":"You're right. I was thinking that he could be my father.","TWN":"沒錯，我確實是這麼想的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"혹시 침식파에 오래 노출되면 통찰력이 생겨서 남의 생각을 꿰뚫어 볼 수 있는 건가요?","JPN":"もしかして、侵食波に長時間晒されると、人の考えていることが見抜けるようになるんでしょうか？","ENG":"If you're exposed to Corruption rays for a long time, do you gain insight to know what other people are thinking?","TWN":"不過……如果長時間暴露在侵蝕波中，是不是會獲得看穿別人的想法的洞察力？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아니면 카운터 능력이 제 머릿속을 파헤치는 것?!","JPN":"それともカウンターとしての能力！？","ENG":"Or did you use your Counter ability to get inside my head?!","TWN":"還是你在用制裁者能力偷窺我的腦子？!"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으윽…… 그동안 속으로 못 미덥다고 한 것 사과할게요! 더는 제 머리를 훑지 말아주세요!","JPN":"ううっ……ずっと内心頼りないと思っていたのは謝ります！　もう頭の中を読むのはやめてください！","ENG":"Erm... I'm sorry for thinking that you were untrustworthy in the head! So, please stop reading my mind!","TWN":"呃呃……我之前心裡偷偷覺得你不可靠，我跟你道歉！請不要再窺視我的腦袋！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 뭐 그런 능력은 아니지만, 평소에 저를 보며 그런 생각을 하고 계셨군요.","JPN":"あはは、そんな能力は持っていませんが、いつも私のことをそう思っていたんですね。","ENG":"Ah hah hah. Well, I can't read minds, but I now know what you thought of me.","TWN":"呵呵呵。那不是我的能力，但原來你是這麼看我的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으윽…… 죄송해요.","JPN":"ううっ……すみません。","ENG":"Ooh... I'm sorry.","TWN":"呃呃……對不起。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저도 그 마음. 잘 알고 있어요.","JPN":"その気持ちはよくわかります。","ENG":"I understand where you're coming from.","TWN":"我也明白那種心情。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"가족이란 건, 보이지 않으면 찾고 싶은 법이니까.","JPN":"家族って、そばにいないと会いたくなる存在ですからね。","ENG":"Everyone wants to go look for their family when they can't see them.","TWN":"家人就是這樣，見不到的時候就會特別想念。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이제 와서 말하기엔 좀 뭐하지만, 저는 생각보다 당신에 대해 조금 알고 있거든요.","JPN":"言うのが遅れましたが、私はあなたが思っている以上に、あなたについて知っています。","ENG":"It might be kind of awkward to say this to you now, but I know more about you than you think.","TWN":"現在說出來有點奇怪，但其實我對你了解的比你想像中還多一點。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"지금 알려드릴 수 있는 건, 당신의 이름이 무엇인지 아는 정도?","JPN":"今、明かせるのは、あなたの名前を知っていることぐらいですね。","ENG":"What I can tell you right now is maybe your name?","TWN":"差不多就是能叫出你的名字的程度？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 독심술 능력자였어…….","JPN":"やっぱりテレパシー能力者だ……","ENG":"I knew it... So you can read minds...","TWN":"果然是讀心術能力者……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"답답하시겠지만 조금만 참아주세요.\xA0","JPN":"もどかしいと思いますが、もう少し我慢してください。\xA0","ENG":"I know it might be a little frustrating, but bear with me here.\xA0","TWN":"雖然讓人心急，但請稍微忍耐一下。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"정보 오염은 타인이 해결해주기 어려운 부분도 있거든요.","JPN":"情報汚染は私たちにはどうしようもできない場合が多いのです。","ENG":"Data corruption is difficult for others to resolve it for you.","TWN":"資訊污染是很難由外人解決的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"우선 가시죠. 의문점은 얼른 해소해야 하지 않겠어요?","JPN":"とりあえず、行きましょう。真偽を確認するために。","ENG":"First, let's get going. Shouldn't you quench your curiosity?","TWN":"先走吧，你不是還有很多疑惑嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};